def seed_current_enrollments(apps, schema_editor):
    StudentProfile = apps.get_model('students', 'StudentProfile')
    StudyGroup = apps.get_model('academics', 'StudyGroup')
    StudentEnrollment = apps.get_model('students', 'StudentEnrollment')

    students = StudentProfile.objects.exclude(study_group_id__isnull=True).only('id', 'study_group_id')
