        group = StudyGroup.objects.only('id', 'academic_year_id').get(pk=student.study_group_id)
        StudentEnrollment.objects.get_or_create(
            student_id=student.pk,
            academic_year_id=group.academic_year_id,
            defaults={
                'study_group_id': group.pk,
                'status': 'active',
            },
        )


